import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Helper function to map weather conditions to appropriate icons
function getWeatherIcon(condition: string): string {
  const iconMap: Record<string, string> = {
    'Sunny': 'sun',
    'Cloudy': 'cloud',
    'Rainy': 'cloud-rain',
    'Snowy': 'cloud-snow',
    'Stormy': 'cloud-lightning',
    'Windy': 'wind',
    'Foggy': 'cloud-fog',
    'Partly Cloudy': 'cloud-sun',
    'Clear': 'moon',
  };
  return iconMap[condition] || 'cloud';
}


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header with city name */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>{props.city}</Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
            Current Weather
          </Text>
        </Stack>

        {/* Main weather card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-6)" align="center">
            {/* Temperature and condition section */}
            <Stack gap="var(--ggui-spacing-4)" align="center">
              <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)">
                {props.temperature}°{props.unit}
              </Text>
              <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center" justify="center">
                <Icon name={getWeatherIcon(props.condition)} size={48} color="var(--ggui-color-primary-500)" />
                <Text size="lg" weight="medium">
                  {props.condition}
                </Text>
              </Stack>
            </Stack>

            {/* Divider */}
            <Divider margin="var(--ggui-spacing-4)" />

            {/* Weather details grid */}
            <Row gap="var(--ggui-spacing-8)" justify="around" align="center" wrap>
              <Stack gap="var(--ggui-spacing-1)" align="center">
                <Icon name="droplets" size={24} color="var(--ggui-color-info-500)" />
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Humidity
                </Text>
                <Text size="lg" weight="medium">
                  {props.humidity}%
                </Text>
              </Stack>

              <Stack gap="var(--ggui-spacing-1)" align="center">
                <Icon name="wind" size={24} color="var(--ggui-color-warning-500)" />
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Wind Speed
                </Text>
                <Text size="lg" weight="medium">
                  {props.windSpeed} km/h
                </Text>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-day forecast */}
        {props.forecast && props.forecast.length > 0 && (
          <Stack gap="var(--ggui-spacing-3)">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              5-DAY FORECAST
            </Text>
            <Row gap="var(--ggui-spacing-3)" wrap>
              {props.forecast.map((day, idx) => (
                <Card key={idx} padding="var(--ggui-spacing-4)" shadow="sm" border>
                  <Stack gap="var(--ggui-spacing-2)" align="center">
                    <Text variant="label" size="sm">
                      {day.day || `Day ${idx + 1}`}
                    </Text>
                    <Icon name={day.icon || 'cloud'} size={32} />
                    <Stack gap="var(--ggui-spacing-1)" align="center">
                      <Text variant="bodySmall" color="var(--ggui-color-primary-600)" weight="medium">
                        {day.high}°
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        {day.low}°
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              ))}
            </Row>
          </Stack>
        )}
      </Stack>
    </Container>

  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const submit = useAction<ActionSubmitPayload>('submit');

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation state
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Validate email format
  const isValidEmail = useCallback((value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  }, []);

  // Validate step 1 (name and email)
  const isStep1Valid = useCallback((): boolean => {
    let valid = true;
    if (!name.trim()) {
      setNameError('Name is required');
      valid = false;
    } else {
      setNameError('');
    }
    if (!email.trim()) {
      setEmailError('Email is required');
      valid = false;
    } else if (!isValidEmail(email)) {
      setEmailError('Please enter a valid email address');
      valid = false;
    } else {
      setEmailError('');
    }
    return valid;
  }, [name, email, isValidEmail]);

  // Check if next button should be disabled
  const isNextDisabled = useMemo((): boolean => {
    if (currentStep === 1) {
      return !name.trim() || !email.trim() || !isValidEmail(email);
    }
    if (currentStep === 2) {
      return !satisfaction;
    }
    return false;
  }, [currentStep, name, email, satisfaction, isValidEmail]);

  // Handle next button
  const handleNext = useCallback((): void => {
    if (currentStep === 1 && !isStep1Valid()) {
      return;
    }
    if (currentStep < 5) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep, isStep1Valid]);

  // Handle back button
  const handleBack = useCallback((): void => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  // Handle feature toggle
  const handleFeatureToggle = useCallback((feature: string): void => {
    setFeatures((prev) => 
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  }, []);

  // Handle submit
  const handleSubmit = useCallback((): void => {
    submit({
      name,
      email,
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments,
    });
  }, [name, email, satisfaction, features, comments, submit]);

  // Calculate progress percentage
  const progressPercent = useMemo((): number => {
    return Math.round(((currentStep - 1) / 4) * 100);
  }, [currentStep]);

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-3)">
          <Heading level={2}>Survey Form</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Step {currentStep === 5 ? 'Review' : currentStep} of 5
          </Text>
          <Progress value={progressPercent} max={100} size="md" />
        </Stack>

        {/* Step 1: Name and Email */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Your Information</Heading>
              <Input
                label="Name"
                placeholder="Enter your full name"
                value={name}
                onChange={setName}
                error={nameError}
                required
              />
              <Input
                label="Email"
                type="email"
                placeholder="Enter your email address"
                value={email}
                onChange={setEmail}
                error={emailError}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Satisfaction Rating</Heading>
              <RadioGroup
                label="How satisfied are you with our service?"
                value={satisfaction}
                onChange={setSatisfaction}
                options={props.satisfactionLabels.map((label, index) => ({
                  value: String(index + 1),
                  label: label,
                }))}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Feature Interests</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Select the features you're interested in:
              </Text>
              <Stack gap="var(--ggui-spacing-2)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={() => handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                placeholder="Tell us anything else you'd like to share (optional)"
                value={comments}
                onChange={setComments}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Review Step (after step 4) */}
        {currentStep === 5 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review Your Answers</Heading>
              <Stack gap="var(--ggui-spacing-3)">
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                    <Text variant="body">{name}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                    <Text variant="body">{email}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction</Text>
                     <Text variant="body">{satisfaction ? props.satisfactionLabels[parseInt(satisfaction, 10) - 1] : 'Not answered'}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Features</Text>
                    <Text variant="body">{features.length > 0 ? features.join(', ') : 'None selected'}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments</Text>
                    <Text variant="body">{comments || '(no comments)'}</Text>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          {currentStep < 5 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={isNextDisabled}
            >
              Next
            </Button>
          )}
          {currentStep === 5 && (
            <Button
              variant="primary"
              onClick={handleSubmit}
            >
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

