// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Task card for displaying individual task
interface TaskCardProps {
  task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };
  columns: Array<{ id?: string; name?: string }>;
  onMove: (taskId: string, newColumn: string) => void;
  onEdit: (taskId: string, newTitle: string) => void;
  currentColumn: string;
}

function TaskCard({ task, columns, onMove, onEdit, currentColumn }: TaskCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title || '');
  const [showMoveMenu, setShowMoveMenu] = useState(false);
  const moveMenuRef = useRef<HTMLDivElement>(null);

  // Priority badge colors
  const priorityColor = task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'success';
  const priorityLabel = (task.priority || 'low').charAt(0).toUpperCase() + (task.priority || 'low').slice(1);

  // Handle click outside move menu
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (moveMenuRef.current && !moveMenuRef.current.contains(event.target as Node)) {
        setShowMoveMenu(false);
      }
    }
    if (showMoveMenu) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
    }
  }, [showMoveMenu]);

  const handleSaveEdit = () => {
    if (editTitle.trim()) {
      onEdit(task.id || '', editTitle);
    }
    setIsEditing(false);
  };

  const handleMoveClick = (columnId: string) => {
    onMove(task.id || '', columnId);
    setShowMoveMenu(false);
  };

  return (
    <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="md">
      <Stack gap="var(--ggui-spacing-2)">
        {/* Title / Edit */}
        {isEditing ? (
          <Input
            label="Task title"
            value={editTitle}
            onChange={setEditTitle}
            onBlur={handleSaveEdit}
            autoFocus
          />
        ) : (
          <Row align="center" justify="between" gap="var(--ggui-spacing-2)">
            <Text
              variant="body"
              as={Clickable}
              onClick={() => setIsEditing(true)}
              style={{ cursor: 'pointer', flex: 1 }}
            >
              {task.title || 'Untitled'}
            </Text>
            <Button
              size="xs"
              variant="ghost"
              onClick={() => setIsEditing(true)}
            >
              <Icon name="edit-2" size={14} />
            </Button>
          </Row>
        )}

        {/* Priority Badge */}
        <Badge variant={priorityColor} size="sm">
          {priorityLabel}
        </Badge>

        {/* Assignee & Due Date */}
        <Row align="center" gap="var(--ggui-spacing-3)" justify="between">
          {task.assignee && (
            <Tooltip content={task.assignee} position="bottom">
              <Avatar name={task.assignee} size="sm" />
            </Tooltip>
          )}
          {task.dueDate && (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              {new Date(task.dueDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
            </Text>
          )}
        </Row>

        {/* Move Button/Menu */}
        <Box position="relative" ref={moveMenuRef}>
          <Button
            size="xs"
            variant="outline"
            onClick={() => setShowMoveMenu(!showMoveMenu)}
            fullWidth
          >
            Move to...  <Icon name="chevron-down" size={12} />
          </Button>

          {showMoveMenu && (
            <Box
              background="var(--ggui-color-surface)"
              borderRadius="var(--ggui-shape-radius-md)"
              padding="var(--ggui-spacing-1)"
              style={{
                position: 'absolute',
                top: '100%',
                left: 0,
                right: 0,
                marginTop: 'var(--ggui-spacing-1)',
                border: '1px solid var(--ggui-color-outline)',
                zIndex: 10,
              }}
            >
              <Stack gap="0">
                {columns.map((col) => (
                  col.id !== currentColumn && (
                    <Button
                      key={col.id}
                      variant="ghost"
                      size="sm"
                      onClick={() => handleMoveClick(col.id || '')}
                      style={{ justifyContent: 'flex-start', width: '100%' }}
                    >
                      {col.name}
                    </Button>
                  )
                ))}
              </Stack>
            </Box>
          )}
        </Box>
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local state
  const [tasks, setTasks] = useState(props.tasks || []);
  const [newTaskColumn, setNewTaskColumn] = useState(props.columns?.[0]?.id || 'todo');
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [showAddTask, setShowAddTask] = useState<string | null>(null); // Column ID for showing add task form
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Update tasks from stream
  useEffect(() => {
    if (taskChanged.latest) {
      const latestTask = taskChanged.latest.task;
      if (taskChanged.latest.action === 'delete' && latestTask?.id) {
        setTasks((prev) => prev.filter((t) => t.id !== latestTask.id));
      } else if (latestTask?.id) {
        setTasks((prev) => {
          const existingIndex = prev.findIndex((t) => t.id === latestTask.id);
          if (existingIndex > -1) {
            const updated = [...prev];
            updated[existingIndex] = { ...updated[existingIndex], ...latestTask };
            return updated;
          } else {
            return [...prev, latestTask];
          }
        });
      }
    }
  }, [taskChanged.latest]);

  // Handle task move
  const handleMoveTask = useCallback(
    (taskId: string, newColumn: string) => {
      setTasks((prev) =>
        prev.map((t) =>
          t.id === taskId ? { ...t, column: newColumn } : t
        )
      );
      taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
    },
    [taskUpdate]
  );

  // Handle task edit
  const handleEditTask = useCallback(
    (taskId: string, newTitle: string) => {
      setTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t))
      );
      taskUpdate({ action: 'edit', taskId, data: { column: '' } });
    },
    [taskUpdate]
  );

  // Handle add task
  const handleAddTask = useCallback(
    (columnId: string) => {
      if (!newTaskTitle.trim()) return;
      const newTask = {
        id: `task-${Date.now()}`,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
      };
      setTasks((prev) => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setShowAddTask(null);
    },
    [newTaskTitle, newTaskPriority, taskUpdate]
  );

  // Get tasks for a column
  const getTasksForColumn = useCallback(
    (columnId: string) => {
      return tasks.filter((t) => t.column === columnId);
    },
    [tasks]
  );

  // Summary stats
  const totalTasks = tasks.length;
  const completedTasks = getTasksForColumn(props.columns?.[props.columns.length - 1]?.id || 'done').length;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row align="center" justify="between" gap="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3}>Task Board</Heading>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {completedTasks} of {totalTasks} completed
              </Text>
            </Stack>
            <Progress
              value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0}
              variant="success"
              size="md"
              style={{ minWidth: '200px' }}
            />
          </Row>
        </Card>

        {/* Kanban Columns */}
        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {props.columns?.map((column) => {
            const columnTasks = getTasksForColumn(column.id || '');
            return (
              <Box
                key={column.id}
                style={{
                  flex: '0 0 calc(33.333% - 11px)',
                  minWidth: '300px',
                }}
              >
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Column Header */}
                  <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                    <Row align="center" justify="between" gap="var(--ggui-spacing-2)">
                      <Stack gap="var(--ggui-spacing-1)">
                        <Heading level={4}>{column.name}</Heading>
                        <Badge variant="secondary" size="sm">
                          {columnTasks.length}
                        </Badge>
                      </Stack>
                    </Row>
                  </Box>

                  {/* Tasks */}
                  <Stack gap="var(--ggui-spacing-3)" align="stretch">
                    {columnTasks.map((task) => (
                      <TaskCard
                        key={task.id}
                        task={task}
                        columns={props.columns || []}
                        onMove={handleMoveTask}
                        onEdit={handleEditTask}
                        currentColumn={column.id || ''}
                      />
                    ))}
                  </Stack>

                  {/* Add Task Form or Button */}
                  {showAddTask === column.id ? (
                    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md" border={false} background="var(--ggui-color-primary-50)">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          placeholder="Enter task title"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          autoFocus
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(val) => setNewTaskPriority(val as 'low' | 'medium' | 'high')}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                        />
                        <Row gap="var(--ggui-spacing-2)" justify="end">
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => {
                              setShowAddTask(null);
                              setNewTaskTitle('');
                              setNewTaskPriority('medium');
                            }}
                          >
                            Cancel
                          </Button>
                          <Button
                            variant="primary"
                            size="sm"
                            onClick={() => handleAddTask(column.id || '')}
                          >
                            Create
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      variant="outline"
                      fullWidth
                      onClick={() => setShowAddTask(column.id || '')}
                    >
                      + Add Task
                    </Button>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}
}

