}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// Helper function to render star rating
function StarRating({ rating }: { rating: number }) {
  const stars = Array.from({ length: 5 }, (_, i) => i + 1);
  return (
    <Row gap="var(--ggui-spacing-1)" align="center">
      {stars.map((star) => (
        <Icon
          key={star}
          name="star"
          size={16}
          color={star <= Math.round(rating) ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
        />
      ))}
    </Row>
  );
}

// Helper function to format price with currency
function formatPrice(price: number, currency: string = 'USD') {
  const symbols: { [key: string]: string } = {
    USD: '$',
    EUR: '€',
    GBP: '£',
    JPY: '¥',
  };
  const symbol = symbols[currency] || currency;
  return `${symbol}${price.toFixed(2)}`
}

// Helper function to parse specifications
function parseSpecifications(specs: unknown[]): Array<{ key: string; value: string }> {
  if (!Array.isArray(specs)) return [];
  return specs.map((spec, idx) => {
    if (typeof spec === 'object' && spec !== null) {
      const entry = spec as Record<string, unknown>;
      return {
        key: String(entry.key || entry.name || `Spec ${idx + 1}`),
        value: String(entry.value || entry.description || ''),
      };
    }
    return { key: `Spec ${idx + 1}`, value: String(spec) };
  });
}

// Helper function to parse reviews
interface ParsedReview {
  author: string;
  rating: number;
  text: string;
  date: string;
}
function parseReviews(reviews: unknown[]): ParsedReview[] {
  if (!Array.isArray(reviews)) return [];
  return reviews.map((review, idx) => {
    if (typeof review === 'object' && review !== null) {
      const r = review as Record<string, unknown>;
      return {
        author: String(r.author || r.name || `Reviewer ${idx + 1}`),
        rating: Number(r.rating || 5),
        text: String(r.text || r.content || r.comment || ''),
        date: r.date instanceof Date ? r.date.toLocaleDateString() : String(r.date || new Date().toLocaleDateString()),
      };
    }
    return { author: `Reviewer ${idx + 1}`, rating: 5, text: String(review), date: new Date().toLocaleDateString() };
  });
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State management
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Handle quantity changes
  const handleQuantityChange = useCallback((value: number) => {
    const newQty = Math.max(1, Math.min(value, props.product.stock || 0));
    setQuantity(newQty);
  }, [props.product.stock]);

  // Handle increment/decrement
  const incrementQuantity = useCallback(() => {
    handleQuantityChange(quantity + 1);
  }, [quantity, handleQuantityChange]);

  const decrementQuantity = useCallback(() => {
    handleQuantityChange(quantity - 1);
  }, [quantity, handleQuantityChange]);

  // Handle Add to Cart
  const handleAddToCart = useCallback(() => {
    if (props.product && props.product.id && props.product.stock && props.product.stock > 0) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product, quantity, addToCart]);

  // Parse specifications and reviews
  const specifications = useMemo(() => parseSpecifications(props.product?.specifications || []), [props.product?.specifications]);
  const reviews = useMemo(() => parseReviews(props.product?.reviews || []), [props.product?.reviews]);

