                  {spec.value}
                </Text>
              </Row>
            ))}
          </Stack>
        </Box>
      ) : (
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
          No specifications available
        </Text>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: reviews.length > 0 ? (
        <Stack gap="var(--ggui-spacing-4)">
          {reviews.map((review, idx) => (
            <Card key={idx} padding="var(--ggui-spacing-4)" shadow="sm">
              <Stack gap="var(--ggui-spacing-2)">
                <Row gap="var(--ggui-spacing-3)" justify="between" align="center">
