                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                      {formatTime(group.items[group.items.length - 1].timestamp)}
                    </Text>
                  )}
                </Stack>
              );
            })
          )}
          <div ref={messagesEndRef} />
        </Card>

        {/* Input Area */}
        <Stack direction="vertical" gap="var(--ggui-spacing-3)" style={{ width: '100%' }}>
          <TextArea
            label="Message"
            placeholder="Type your message here... (Shift+Enter for new line)"
            value={inputValue}
            onChange={setInputValue}
            onKeyDown={handleKeyDown}
            rows={3}
          />
          <Button
            variant="primary"
            fullWidth={false}
            onClick={handleSendMessage}
            disabled={!inputValue.trim()}
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

