/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Helper component for individual stock card
function StockCard({ stock, hasFlash }: { stock: { symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }; hasFlash: boolean }) {
  const isPositive = (stock.change ?? 0) >= 0;
  const changeColor = isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';
  const borderColor = isPositive ? 'var(--ggui-color-success-200)' : 'var(--ggui-color-error-200)';
  const arrow = isPositive ? '▲' : '▼';
  const flashColor = isPositive ? 'var(--ggui-color-success-100)' : 'var(--ggui-color-error-100)';

  return (
    <Card
      padding="var(--ggui-spacing-4)"
      shadow="md"
      border={true}
      radius="lg"
      style={{
        borderColor: borderColor,
        borderWidth: '2px',
        animation: hasFlash ? 'ggui-flash 600ms ease-out' : 'none',
        '--ggui-flash-color': flashColor,
      } as React.CSSProperties}
    >
      <Stack gap="var(--ggui-spacing-3)">
         <Heading level={4} color="var(--ggui-color-onSurface)">
          {stock.symbol || 'N/A'}
        </Heading>
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
          {stock.name || 'Unknown'}
        </Text>
        <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface)">
          ${stock.price ? stock.price.toFixed(2) : '0.00'}
        </Text>
        <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2)">
          <Text color={changeColor} weight="semibold">
            {arrow} {stock.change ? Math.abs(stock.change).toFixed(2) : '0.00'} ({stock.changePercent ? stock.changePercent.toFixed(2) : '0.00'}%)
          </Text>
        </Stack>
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for merged stock data and last update timestamp
  const [stocks, setStocks] = useState(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [flashingSymbols, setFlashingSymbols] = useState<Set<string>>(new Set());
  const flashTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Merge stream updates into stock data
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setStocks((prevStocks) => {
        const updated = prevStocks.map((stock) => {
          if (stock.symbol === update.symbol) {
            return {
              ...stock,
              price: update.price ?? stock.price,
              change: update.change ?? stock.change,
              changePercent: update.changePercent ?? stock.changePercent,
            };
          }
          return stock;
        });
        return updated;
      });
      setLastUpdated(new Date());

      // Trigger flash animation for the updated symbol
      if (update.symbol) {
        setFlashingSymbols((prev) => new Set([...prev, update.symbol!]));
        if (flashTimeoutRef.current) clearTimeout(flashTimeoutRef.current);
        flashTimeoutRef.current = setTimeout(() => {
          setFlashingSymbols(new Set());
        }, 600);
      }
    }
  }, [priceUpdate.latest]);

  // Update timestamp in real-time
  useEffect(() => {
    const interval = setInterval(() => {
      setLastUpdated(new Date());
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  // Determine market status color
  const marketStatusVariant = marketStatus.latest?.status === 'open' ? 'success' : 'default';

  return (
    <>
      <style>{`
        @keyframes ggui-flash {
          0% { background-color: var(--ggui-flash-color, var(--ggui-color-primary-100)); }
          100% { background-color: transparent; }
        }
      `}</style>
      <MotionKeyframes />
      <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header Section */}
        <Stack gap="var(--ggui-spacing-4)" align="start">
          <Row justify="between" align="center" wrap={false}>
            <Heading level={1} color="var(--ggui-color-onSurface)">
              Market Watch
            </Heading>
            {marketStatus.latest && (
              <Badge variant={marketStatusVariant} size="md">
                {marketStatus.latest.status === 'open' ? '🟢 Market Open' : '🔴 Market Closed'}
              </Badge>
            )}
          </Row>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Last Updated: {lastUpdated.toLocaleTimeString()}
          </Text>
        </Stack>

        {/* Stocks Grid */}
        <CardGrid columns={{ sm: 1, md: 3 }} gap={24}>
          {stocks && stocks.length > 0 ? (
            stocks.map((stock) => (
              <StockCard
                key={stock.symbol || Math.random()}
                stock={stock}
                hasFlash={flashingSymbols.has(stock.symbol ?? '')}
              />
            ))
          ) : (
            <Text color="var(--ggui-color-onSurfaceVariant)">No stocks available</Text>
          )}
        </CardGrid>
      </Stack>
      </Container>
    </>
  );
}

