/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // State for 3-step wizard
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || (props.avatarOptions.length > 0 ? props.avatarOptions[0] : ''),
    role: props.initialProfile.role || (props.roleOptions.length > 0 ? props.roleOptions[0] : ''),
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });

  // Validation state
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Email validation
  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  // Validate current step
  const validateStep = (step: number): boolean => {
    const newErrors: Record<string, string> = {};
    if (step === 1) {
      if (!formData.name.trim()) newErrors.name = 'Name is required';
      if (!formData.email.trim()) newErrors.email = 'Email is required';
      else if (!validateEmail(formData.email)) newErrors.email = 'Invalid email format';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  // Check if Step 1 has validation errors
  const isStep1Invalid = useMemo(() => {
    const stepErrors: Record<string, string> = {};
    if (!formData.name.trim()) stepErrors.name = 'Name is required';
    if (!formData.email.trim()) stepErrors.email = 'Email is required';
    else if (!validateEmail(formData.email)) stepErrors.email = 'Invalid email format';
    return Object.keys(stepErrors).length > 0;
  }, [formData.name, formData.email]);

  // Navigate to next step
  const handleNext = () => {
    if (validateStep(currentStep)) {
      setCurrentStep(currentStep + 1);
    }
  };

  // Navigate to previous step
  const handleBack = () => {
    setCurrentStep(currentStep - 1);
    setErrors({});
  };

  // Handle form submission
  const handleComplete = () => {
    complete({
      name: formData.name,
      email: formData.email,
