const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];

function getPriorityVariant(priority: 'low' | 'medium' | 'high' | undefined): 'success' | 'warning' | 'error' {
  if (priority === 'high') return 'error';
  if (priority === 'medium') return 'warning';
  return 'success';
}

function getInitials(name: string | undefined): string {
  if (!name) return 'NA';
  const parts = name.trim().split(' ').filter(Boolean);
  if (!parts.length) return 'NA';
  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
  return `${parts[0][0]}${parts[1][0]}`.toUpperCase();
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [tasksState, setTasksState] = useState<Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>>(props.tasks || []);
  const [addFormColumnId, setAddFormColumnId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');

  useEffect(() => {
    setTasksState(props.tasks || []);
  }, [props.tasks]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const incoming = taskChanged.latest.task;
    const incomingId = incoming.id || '';
    if (!incomingId) return;

    setTasksState((prev) => {
      if (taskChanged.latest?.action === 'delete') {
        return prev.filter((task) => (task.id || '') !== incomingId);
      }
      const existingIndex = prev.findIndex((task) => (task.id || '') === incomingId);
      if (existingIndex === -1) {
        return [...prev, incoming];
      }
      const next = [...prev];
      next[existingIndex] = { ...next[existingIndex], ...incoming };
      return next;
    });
  }, [taskChanged.latest]);

  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>> = {};
    (props.columns || []).forEach((col) => {
      const colId = col.id || '';
      grouped[colId] = [];
    });
    (tasksState || []).forEach((task) => {
      const colId = task.column || '';
      if (!grouped[colId]) grouped[colId] = [];
      grouped[colId].push(task);
    });
    return grouped;
  }, [tasksState, props.columns]);

  const totalTasks = (tasksState || []).length;
  const doneColumnId = ((props.columns || []).find((col) => (col.name || '').toLowerCase() === 'done')?.id) || 'done';
  const completedTasks = (tasksState || []).filter((task) => (task.column || '') === doneColumnId).length;

  const moveTask = useCallback((taskId: string, targetColumn: string) => {
    if (!taskId || !targetColumn) return;
    setTasksState((prev) => prev.map((task) => ((task.id || '') === taskId ? { ...task, column: targetColumn } : task)));
    taskUpdate({
      action: 'move',
      taskId,
      data: { column: targetColumn },
    });
  }, [taskUpdate]);

  const startEdit = useCallback((taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle);
  }, []);

  const saveEdit = useCallback((taskId: string) => {
    if (!editingTitle.trim()) return;
    const updatedColumn = (tasksState.find((task) => (task.id || '') === taskId)?.column || 'todo');
    const updatedTitle = editingTitle.trim();
    setTasksState((prev) => prev.map((task) => ((task.id || '') === taskId ? { ...task, title: updatedTitle } : task)));
    taskUpdate({
      action: 'edit',
      taskId,
      data: { column: updatedColumn, title: updatedTitle } as { column: string },
    });
    setEditingTaskId(null);
    setEditingTitle('');
  }, [editingTitle, taskUpdate, tasksState]);

  const createTask = useCallback(() => {
    if (!newTaskTitle.trim()) return;
    const newId = `task-${Date.now()}`;
    const todoColumnId = (props.columns || []).find((col) => (col.name || '').toLowerCase() === 'to do')?.id || 'todo';
    const createdTask = {
      id: newId,
      title: newTaskTitle.trim(),
      priority: newTaskPriority,
      assignee: 'Unassigned',
      column: todoColumnId,
      dueDate: '',
    } as { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };

    setTasksState((prev) => [...prev, createdTask]);
    taskUpdate({
      action: 'create',
      taskId: newId,
      data: { column: createdTask.column || 'todo', title: createdTask.title || '', priority: createdTask.priority || 'medium', assignee: createdTask.assignee || '', dueDate: createdTask.dueDate || '' } as { column: string },
    });
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddFormColumnId(null);
  }, [newTaskTitle, newTaskPriority, taskUpdate, props.columns]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Row justify="between" align="center" gap="var(--ggui-spacing-3)">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3}>Team Task Board</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                {completedTasks} completed of {totalTasks} total tasks
              </Text>
            </Stack>
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Badge variant="primary">Total: {totalTasks}</Badge>
              <Badge variant="success">Done: {completedTasks}</Badge>
              <Badge variant={taskChanged.latest ? 'info' : 'default'}>
                Updates: {taskChanged.all.length}
              </Badge>
            </Row>
          </Row>
        </Card>

        {(!props.columns || props.columns.length === 0) && (
          <Alert variant="warning" title="No columns configured">
            Add column definitions to render the board.
          </Alert>
        )}

        {(props.columns && props.columns.length > 0) && (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {(props.columns || []).map((column) => {
              const columnId = column.id || '';
              const columnTasks = tasksByColumn[columnId] || [];
              return (
                <Card key={columnId || column.name} padding="var(--ggui-spacing-4)" shadow="sm" border>
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row justify="between" align="center">
                      <Heading level={4}>{column.name || 'Untitled'}</Heading>
                      <Badge variant="default">{columnTasks.length}</Badge>
                    </Row>
                    <Divider margin="var(--ggui-spacing-1)" />

                    <Stack gap="var(--ggui-spacing-3)">
                      {columnTasks.length === 0 && (
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                          No tasks yet.
                        </Text>
                      )}

                      {columnTasks.map((task) => {
                        const taskId = task.id || '';
                        const isEditing = editingTaskId === taskId;
                        const moveOptions = (props.columns || []).filter((c) => (c.id || '') !== (task.column || '')).map((c) => ({
                          value: c.id || '',
                          label: c.name || '',
                        }));

                        return (
                          <Card key={taskId} padding="var(--ggui-spacing-3)" border shadow="none">
                            <Stack gap="var(--ggui-spacing-2)">
                              <Row justify="between" align="center" gap="var(--ggui-spacing-2)">
                                {isEditing ? (
                                  <Input
                                    label="Edit task title"
                                    value={editingTitle}
                                    onChange={setEditingTitle}
                                    placeholder="Task title"
                                  />
                                ) : (
                                  <Text
                                    as={Clickable}
                                    onClick={() => startEdit(taskId, task.title || '')}
                                    onDoubleClick={() => startEdit(taskId, task.title || '')}
                                    variant="label"
                                    color="var(--ggui-color-onSurface)"
                                  >
                                    {task.title || 'Untitled task'}
                                  </Text>
                                )}
                                <Badge variant={getPriorityVariant(task.priority)}>{task.priority || 'low'}</Badge>
                              </Row>

                              <Row align="center" justify="between">
                                <Row align="center" gap="var(--ggui-spacing-2)">
                                  <Avatar name={task.assignee || getInitials(task.assignee)} size="sm" />
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                    {task.assignee || getInitials(task.assignee)}
                                  </Text>
                                </Row>
                                {task.dueDate ? (
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                    Due: {task.dueDate}
                                  </Text>
                                ) : (
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                    No due date
                                  </Text>
                                )}
                              </Row>

                              <Row gap="var(--ggui-spacing-2)" align="center">
                                {isEditing ? (
                                  <Button variant="primary" size="sm" onClick={() => saveEdit(taskId)}>
                                    Save
                                  </Button>
                                ) : (
                                  <Button variant="outline" size="sm" onClick={() => startEdit(taskId, task.title || '')}>
                                    Edit
                                  </Button>
                                )}
                                <Select
                                  label="Move task"
                                  value=""
                                  onChange={(value) => moveTask(taskId, value)}
                                  placeholder="Move to..."
                                  options={moveOptions}
                                />
                              </Row>
                            </Stack>
                          </Card>
                        );
                      })}
                    </Stack>

                    {addFormColumnId === columnId ? (
                      <Card padding="var(--ggui-spacing-3)" border shadow="none">
                        <Stack gap="var(--ggui-spacing-2)">
                          <Input
                            label="Task title"
                            value={newTaskTitle}
                            onChange={setNewTaskTitle}
                            placeholder="Enter task title"
                          />
                          <Select
                            label="Priority"
                            value={newTaskPriority}
                            onChange={(value) => setNewTaskPriority(value as 'low' | 'medium' | 'high')}
                            options={PRIORITY_OPTIONS}
                          />
                          <Row gap="var(--ggui-spacing-2)">
                            <Button variant="primary" size="sm" onClick={() => createTask()}>
                              Create
                            </Button>
                            <Button variant="ghost" size="sm" onClick={() => setAddFormColumnId(null)}>
                              Cancel
                            </Button>
                          </Row>
                        </Stack>
                      </Card>
                    ) : (
                      <Button variant="secondary" onClick={() => setAddFormColumnId(columnId)}>
                        Add Task
                      </Button>
                    )}
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>

  );
}

