const CATEGORY_COLORS: Record<string, string> = {
  alkali: 'var(--ggui-color-error-100)',
  'alkaline-earth': 'var(--ggui-color-warning-100)',
  transition: 'var(--ggui-color-primary-100)',
  'post-transition': 'var(--ggui-color-info)',
  'metalloid': 'var(--ggui-color-success-100)',
  'nonmetal': 'var(--ggui-color-success-50)',
