  'lanthanide': 'var(--ggui-color-primary-200)',
  'actinide': 'var(--ggui-color-error-50)',
  unknown: 'var(--ggui-color-surfaceVariant)',
};

function normalizeCategory(category?: string): string {
  if (!category) return 'unknown';
  return category.toLowerCase().replace(/\s+/g, '-');
}

function getCategoryColor(category?: string): string {
  const key = normalizeCategory(category);
  return CATEGORY_COLORS[key] || 'var(--ggui-color-surfaceVariant)';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [query, setQuery] = useState<string>('');
  const [selectedIndex, setSelectedIndex] = useState<number>(-1);

  const safeElements = useMemo(() => {
    return Array.isArray(props.elements) ? props.elements : [];
  }, [props.elements]);

  const filteredElements = useMemo(() => {
    const normalizedQuery = query.trim().toLowerCase();
    if (!normalizedQuery) return safeElements;
    return safeElements.filter((element) => {
      const name = (element.name || '').toLowerCase();
      const symbol = (element.symbol || '').toLowerCase();
      return name.includes(normalizedQuery) || symbol.includes(normalizedQuery);
    });
  }, [safeElements, query]);

  useEffect(() => {
    setSelectedIndex((prev) => {
      if (filteredElements.length === 0) return -1;
      if (prev < 0) return 0;
      if (prev >= filteredElements.length) return 0;
      return prev;
    });
  }, [filteredElements]);

  const selectedElement = useMemo(() => {
    if (selectedIndex < 0 || selectedIndex >= filteredElements.length) return null;
    return filteredElements[selectedIndex];
  }, [filteredElements, selectedIndex]);

  const categories = useMemo(() => {
    const map: Record<string, boolean> = {};
    safeElements.forEach((element) => {
      const key = normalizeCategory(element.category);
      map[key] = true;
