                  </Stack>
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant)">Select an element to view details.</Text>
                )}
              </Stack>
            </Card>

            <Card padding="var(--ggui-spacing-4)">
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={4}>Legend</Heading>
