// Place helper components here if needed
type ChatMessageItem = { sender: string; text: string; timestamp: string };

function normalizeMessage(input?: { sender?: string; text?: string; timestamp?: string }): ChatMessageItem | null {
  if (!input) return null;
  const sender = input.sender ?? 'Unknown';
  const text = input.text ?? '';
  const timestamp = input.timestamp ?? new Date().toISOString();
  if (!text.trim()) return null;
  return { sender, text, timestamp };
}

function formatTimestamp(value: string): string {
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return value;
  return parsed.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [chatMessages, setChatMessages] = useState<ChatMessageItem[]>(() => {
    return (props.messages ?? [])
      .map((msg) => normalizeMessage(msg))
      .filter((msg): msg is ChatMessageItem => msg !== null);
  });
  const [draft, setDraft] = useState<string>('');
  const [typingState, setTypingState] = useState<{ sender: string; active: boolean }>({ sender: '', active: false });
  const scrollRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    const normalized = (props.messages ?? [])
      .map((msg) => normalizeMessage(msg))
      .filter((msg): msg is ChatMessageItem => msg !== null);
    setChatMessages(normalized);
  }, [props.messages]);

  useEffect(() => {
    const latest = normalizeMessage(message.latest ?? undefined);
    if (!latest) return;
    setChatMessages((prev) => [...prev, latest]);
  }, [message.latest]);

  useEffect(() => {
    if (!typing.latest) return;
    setTypingState({
      sender: typing.latest.sender ?? '',
      active: Boolean(typing.latest.active),
    });
  }, [typing.latest]);

  useEffect(() => {
    if (!scrollRef.current) return;
    scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [chatMessages, typingState.active]);

  const groupedMessages = useMemo(() => {
    return chatMessages.reduce<Array<{ sender: string; isCurrentUser: boolean; items: ChatMessageItem[] }>>((acc, item) => {
      const isCurrentUser = item.sender === props.currentUser;
      const previous = acc[acc.length - 1];
      if (previous && previous.sender === item.sender) {
        previous.items.push(item);
      } else {
        acc.push({ sender: item.sender, isCurrentUser, items: [item] });
      }
      return acc;
    }, []);
  }, [chatMessages, props.currentUser]);

  const handleSend = useCallback(() => {
    const trimmed = draft.trim();
    if (!trimmed) return;
    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    sendMessage(payload);
    setChatMessages((prev) => [...prev, { sender: props.currentUser, text: payload.text, timestamp: payload.timestamp }]);
    setDraft('');
  }, [draft, props.currentUser, sendMessage]);

  const handleInputKeyDown = useCallback(
    (event: React.KeyboardEvent<HTMLInputElement>) => {
      if (event.key === 'Enter') {
        event.preventDefault();
        handleSend();
      }
    },
    [handleSend],
  );

  const typingLabel = typingState.active && typingState.sender && typingState.sender !== props.currentUser
    ? `${typingState.sender} is typing...`
    : '';

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Card
        padding="0"
        border
        radius="lg"
        shadow="sm"
      >
