              <Badge variant="primary">{props.participantCount} participants</Badge>
            </Row>
            <Box margin="var(--ggui-spacing-2) 0 0 0">
              <Text variant="caption" color="var(--ggui-color-onContainer)">
                {typingLabel || ' '}
              </Text>
            </Box>
          </Box>

          <Box
            padding="var(--ggui-spacing-4)"
            background="var(--ggui-color-surface)"
            style={{ height: '60vh', overflowY: 'auto' }}
            ref={scrollRef}
          >
            {groupedMessages.length === 0 ? (
              <Box padding="var(--ggui-spacing-6)">
                <Text align="center" color="var(--ggui-color-onSurfaceVariant)">No messages yet</Text>
              </Box>
            ) : (
              <Stack gap="var(--ggui-spacing-3)">
                {groupedMessages.map((group, groupIndex) => (
                  <Stack key={`${group.sender}-${groupIndex}`} gap="var(--ggui-spacing-1)" align={group.isCurrentUser ? 'end' : 'start'}>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{group.sender}</Text>
                    {group.items.map((msg, msgIndex) => (
                      <Box
                        key={`${groupIndex}-${msgIndex}-${msg.timestamp}`}
>
                        <Box
                          padding="var(--ggui-spacing-3)"
                          background={group.isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                          borderRadius="var(--ggui-shape-radius-lg)"
                        >
                          <Stack gap="var(--ggui-spacing-1)">
                            <Text color={group.isCurrentUser ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}>{msg.text}</Text>
                            <Text
                              variant="caption"
                              color={group.isCurrentUser ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}
                              align={group.isCurrentUser ? 'right' : 'left'}
                            >
                              {formatTimestamp(msg.timestamp)}
                            </Text>
                          </Stack>
                        </Box>
                      </Box>
                    ))}
                  </Stack>
                ))}
              </Stack>
            )}
          </Box>

          <Divider margin="0" color="var(--ggui-color-outlineVariant)" />

          <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surface)">
            <Row gap="var(--ggui-spacing-3)" align="end">
              <Box style={{ flex: 1 }}>
                <Input
                  label="Type your message"
                  placeholder="Write a message..."
                  value={draft}
                  onChange={setDraft}
                  onKeyDown={handleInputKeyDown}
                />
              </Box>
              <Box as={Clickable} onClick={handleSend} style={{ alignSelf: 'stretch' }}>
                <Button variant="primary" disabled={!draft.trim()}>Send</Button>
              </Box>
            </Row>
          </Box>
        </Stack>
      </Card>
    </Container>

  );
}

