            {(stocks || []).map((stock, index) => {
              const symbol = stock.symbol || `stock-${index}`;
              const change = stock.change || 0;
              const isPositive = change >= 0;
              const borderColor = isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';
              const textColor = isPositive ? 'var(--ggui-color-success-700)' : 'var(--ggui-color-error-700)';
              const flashActive = flashMap[symbol] && Date.now() - flashMap[symbol] < 1200;

              return (
                <Card
