                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                            {stock.name || 'Unknown Company'}
                          </Text>
                        </Stack>
                        <Badge variant={isPositive ? 'success' : 'error'}>
                          {isPositive ? '▲' : '▼'}
                        </Badge>
                      </Row>

                      <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

                      <Row justify="between" align="end">
                        <Stack gap="var(--ggui-spacing-1)">
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                            Current Price
                          </Text>
                          <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">
                            ${(stock.price || 0).toFixed(2)}
                          </Text>
                        </Stack>
                        <Stack gap="var(--ggui-spacing-1)" align="end">
                          <Text variant="bodySmall" color={textColor}>
                            {change >= 0 ? '+' : ''}{(stock.change || 0).toFixed(2)}
                          </Text>
                          <Text
                            variant="label"
                            color={textColor}
                          >
                            {isPositive ? '▲' : '▼'} {change >= 0 ? '+' : ''}{(stock.changePercent || 0).toFixed(2)}%
                          </Text>
                        </Stack>
                      </Row>
