  const [role, setRole] = useState(props.initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState((props.initialProfile.theme ?? 'light') === 'dark' ? 'dark' : 'light');
  const [showValidation, setShowValidation] = useState(false);

  const emailValid = useMemo(() => EMAIL_REGEX.test(email.trim()), [email]);
  const stepOneValid = useMemo(() => name.trim().length > 0 && emailValid, [name, emailValid]);
  const stepTwoValid = useMemo(() => role.trim().length > 0, [role]);
  const canProceed = step === 1 ? stepOneValid : step === 2 ? stepTwoValid : true;
  const progressValue = useMemo(() => (step / 3) * 100, [step]);

  const nameError = showValidation && name.trim().length === 0 ? 'Name is required' : undefined;
  const emailError = showValidation && email.trim().length === 0 ? 'Email is required' : showValidation && !emailValid ? 'Please enter a valid email' : undefined;
  const roleError = showValidation && step === 2 && role.trim().length === 0 ? 'Role is required' : undefined;

  const nextStep = useCallback(() => {
    if (step === 1 && !stepOneValid) {
      setShowValidation(true);
      return;
    }
    if (step === 2 && !stepTwoValid) {
      setShowValidation(true);
      return;
    }
    setShowValidation(false);
    setStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, [step, stepOneValid, stepTwoValid]);

  const prevStep = useCallback(() => {
    setShowValidation(false);
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const submit = useCallback(() => {
    if (!stepOneValid || !stepTwoValid) {
      setShowValidation(true);
      return;
    }
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar: avatar || (props.avatarOptions[0] ?? '🙂'),
      role: role.trim(),
      emailNotifications,
      theme,
    });
  }, [stepOneValid, stepTwoValid, name, email, avatar, role, emailNotifications, theme, props]);

  useEffect(() => {
    if (!props.avatarOptions.includes(avatar) && props.avatarOptions.length > 0) {
      setAvatar(props.avatarOptions[0]);
    }
  }, [props.avatarOptions, avatar]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              {step === 1 ? 'Profile Setup' : step === 2 ? 'Preferences' : 'Review & Confirm'}
            </Text>
          </Stack>
        </Card>

        <Card
          padding="var(--ggui-spacing-6)"
          shadow="sm"
          radius="lg"
        >
          <Box
            key={step}
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  placeholder="Enter your name"
                  required
                  error={nameError}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="you@example.com"
                  required
                  error={emailError}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Choose an avatar</Text>
                  <Row gap="var(--ggui-spacing-3)" wrap>
                    {props.avatarOptions.slice(0, 4).map((option) => (
                      <Card
                        key={option}
                        as={Clickable}
                        onClick={() => setAvatar(option)}
                        padding="var(--ggui-spacing-3)"
                        radius="md"
                        border
                        style={{
                          borderColor: avatar === option ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                          background: avatar === option ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                          minWidth: '56px',
                          textAlign: 'center',
                        }}
                      >
                        <Text size="2xl" align="center">{option}</Text>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={(props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other']).map((option) => ({ value: option, label: option }))}
                  placeholder="Select your role"
                  required
                  error={roleError}
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Theme preference (Dark mode)"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review & Confirm</Heading>
                <Alert variant="info" title="Please review your details">
                  You can go back to edit any field before completing setup.
                </Alert>
                <Card padding="var(--ggui-spacing-4)" radius="md" shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme === 'dark' ? 'Dark' : 'Light'}</Text></Row>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>
        </Card>

        <Row justify="between" align="center">
          <Button variant="outline" onClick={prevStep} disabled={step === 1}>
            Back
          </Button>
          <Row gap="var(--ggui-spacing-2)">
            {step < 3 ? (
              <Button variant="primary" onClick={nextStep} disabled={!canProceed}>
                Next
              </Button>
            ) : (
              <>
                <Button variant="outline" onClick={prevStep}>
                  Go Back
                </Button>
                <Button variant="primary" onClick={submit}>
                  Complete Setup
                </Button>
              </>
            )}
          </Row>
        </Row>
      </Stack>
    </Container>

  );
}
